module top_module(
          input clk, clear,
          input [7:0] cct_input,
          output reg [7:0] cct_output
			 );reg [7:0] misleading_counter;

always @ (posedge clk)
if (clear == 1'b1) misleading_counter = 8'b10000001;
else if (misleading_counter == 8'b10000001) misleading_counter = 8'b01000010;
else if (misleading_counter == 8'b01000010) misleading_counter = 8'b00100100;
else if (misleading_counter == 8'b00100100) misleading_counter = 8'b00011000;
else if (misleading_counter == 8'b00011000) misleading_counter = 8'b10000001;
else misleading_counter = 8'b10000001;

always @ *
cct_output = misleading_counter;

endmodule
